export const MOCK_PROVERBS: Proverb[] = [
  // --- FAMILLE & COMMUNAUTÉ ---
  { id: '1', text: "Il faut tout un village pour élever un enfant.", translation: "It takes a village to raise a child.", explanation: "L'éducation est une responsabilité collective.", countryId: 'NG', language: 'Yoruba', themeId: 'Famille & Communauté', likesCount: 2500, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigéria' },
  { id: '2', text: "Si tu veux aller vite, marche seul. Si tu veux aller loin, marchons ensemble.", translation: "Go far together.", explanation: "La solidarité est la clé du succès durable.", countryId: 'GH', language: 'Akan', themeId: 'Famille & Communauté', likesCount: 1800, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '3', text: "L'arbre soutenu par ses racines ne craint pas le vent.", translation: "Roots protect the tree.", explanation: "La famille nous donne la force de résister aux épreuves.", countryId: 'CD', language: 'Lingala', themeId: 'Famille & Communauté', likesCount: 950, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '4', text: "Le vieux qui meurt est une bibliothèque qui brûle.", translation: "Elders are libraries.", explanation: "Respect des aînés et de la transmission orale.", countryId: 'ML', language: 'Bambara', themeId: 'Famille & Communauté', likesCount: 3200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '5', text: "Un seul doigt ne peut pas laver la figure.", translation: "One finger can't wash a face.", explanation: "L'importance de l'entraide communautaire.", countryId: 'CI', language: 'Baoulé', themeId: 'Famille & Communauté', likesCount: 450, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '6', text: "Le bâton de la famille se plie mais ne se casse pas.", translation: "Family bonds are flexible.", explanation: "Les liens familiaux sont plus forts que les disputes.", countryId: 'CD', language: 'Kongo', themeId: 'Famille & Communauté', likesCount: 120, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '7', text: "On est mieux là où on a ses attaches.", translation: "Home is where the heart is.", explanation: "Le sentiment d'appartenance à sa communauté.", countryId: 'SN', language: 'Wolof', themeId: 'Famille & Communauté', likesCount: 670, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '8', text: "Les traces de ceux qui marchent ensemble ne s'effacent jamais.", translation: "Strong bonds last.", explanation: "L'amitié et la fraternité marquent la vie.", countryId: 'GA', language: 'Fang', themeId: 'Famille & Communauté', likesCount: 890, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },

  // --- COURAGE & PERSÉVÉRANCE ---
  { id: '9', text: "L'étincelle ne demande pas la permission pour devenir un incendie.", translation: "Courage starts small.", explanation: "L'audace peut transformer une situation.", countryId: 'CD', language: 'Swahili', themeId: 'Courage & Persévérance', likesCount: 1500, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '10', text: "Le lion ne se retourne pas quand un petit chien aboie.", translation: "Focus on your goals.", explanation: "Ne pas se laisser distraire par les critiques.", countryId: 'CI', language: 'Dioula', themeId: 'Courage & Persévérance', likesCount: 2100, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '11', text: "Tomber n'est rien, c'est se relever qui compte.", translation: "Rising is everything.", explanation: "La résilience face à l'échec.", countryId: 'CM', language: 'Ewondo', themeId: 'Courage & Persévérance', likesCount: 3000, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '12', text: "Même le plus grand palmier a commencé par une graine.", translation: "Greatness takes time.", explanation: "Tout grand accomplissement commence petit.", countryId: 'TG', language: 'Ewe', themeId: 'Courage & Persévérance', likesCount: 1300, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '13', text: "La pluie mouille le léopard mais n'efface pas ses taches.", translation: "Identity remains.", explanation: "Les épreuves n'altèrent pas notre vraie nature.", countryId: 'GH', language: 'Akan', themeId: 'Courage & Persévérance', likesCount: 1700, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '14', text: "L'eau qui coule finit par percer le rocher.", translation: "Persistence wins.", explanation: "La persévérance surmonte tous les obstacles.", countryId: 'EG', language: 'Arabe', themeId: 'Courage & Persévérance', likesCount: 880, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Égypte' },
  { id: '15', text: "Le serpent qui veut mordre n'aboie pas.", translation: "Action over words.", explanation: "Les défis les plus sérieux sont silencieux.", countryId: 'CD', language: 'Lingala', themeId: 'Courage & Persévérance', likesCount: 420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '16', text: "Si tu es une enclume, sois patiente ; si tu es un marteau, frappe fort.", translation: "Adapt to your role.", explanation: "Savoir s'adapter selon les circonstances.", countryId: 'GN', language: 'Soussou', themeId: 'Courage & Persévérance', likesCount: 610, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },

  // --- SAGESSE & PATIENCE ---
  { id: '17', text: "Mwana ya nkoko te kozanga nzela", translation: "Vulture's child finds its path.", explanation: "Celui qui est bien guidé trouve toujours sa voie.", countryId: 'CD', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 124, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '18', text: "L'eau chaude n'oublie pas qu'elle a été froide.", translation: "Hot water was once cold.", explanation: "Ne jamais oublier ses origines modestes.", countryId: 'KE', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 890, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '19', text: "La patience est un chemin d'or.", translation: "Patience is golden.", explanation: "Tout vient à point à qui sait attendre.", countryId: 'ML', language: 'Bambara', themeId: 'Sagesse & Patience', likesCount: 2300, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '20', text: "Celui qui ne sait pas d'où il vient ne sait pas où il va.", translation: "Know your origins.", explanation: "Connaître son passé pour construire son futur.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 4500, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '21', text: "Petit à petit, l'oiseau fait son nid.", translation: "Step by step.", explanation: "Le travail régulier mène au succès.", countryId: 'MA', language: 'Arabe', themeId: 'Sagesse & Patience', likesCount: 1900, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '22', text: "On n'apprend pas à un vieux singe à faire des grimaces.", translation: "Experience matters.", explanation: "Respecter la sagesse de l'expérience.", countryId: 'CD', language: 'Luba', themeId: 'Sagesse & Patience', likesCount: 1500, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '23', text: "Le fleuve fait des détours car personne ne lui montre la voie.", translation: "Find your own way.", explanation: "L'autonomie et l'apprentissage personnel.", countryId: 'GH', language: 'Twi', themeId: 'Sagesse & Patience', likesCount: 920, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '24', text: "Si tu cherches une aiguille, ne regarde pas les étoiles.", translation: "Be pragmatic.", explanation: "Il faut chercher des solutions concrètes.", countryId: 'ET', language: 'Amharique', themeId: 'Sagesse & Patience', likesCount: 410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },

  // --- AMOUR & RELATIONS ---
  { id: '25', text: "Là où on s'aime, il ne fait jamais nuit.", translation: "Love brings light.", explanation: "L'amour illumine la vie quotidienne.", countryId: 'CD', language: 'Swahili', themeId: 'Amour & Relations', likesCount: 5000, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '26', text: "L'amour est un piment qui pique mais qu'on adore.", translation: "Love is a spicy chili.", explanation: "La passion malgré ses difficultés.", countryId: 'CM', language: 'Douala', themeId: 'Amour & Relations', likesCount: 1200, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '27', text: "Le cœur n'a pas de genoux pour se plier.", translation: "The heart doesn't bend.", explanation: "On ne force pas les sentiments amoureux.", countryId: 'CI', language: 'Bété', themeId: 'Amour & Relations', likesCount: 840, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '28', text: "Une amitié est une fleur qu'il faut arroser chaque jour.", translation: "Friendship needs care.", explanation: "Les relations demandent de l'attention constante.", countryId: 'MA', language: 'Berbère', themeId: 'Amour & Relations', likesCount: 2200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '29', text: "Qui aime l'arbre, aime aussi les branches.", translation: "Love the whole tree.", explanation: "Aimer quelqu'un, c'est accepter son entourage.", countryId: 'KE', language: 'Kikuyu', themeId: 'Amour & Relations', likesCount: 770, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '30', text: "Le regard est le messager du cœur.", translation: "Eyes are messengers.", explanation: "Les yeux révèlent les sentiments profonds.", countryId: 'TD', language: 'Arabe', themeId: 'Amour & Relations', likesCount: 560, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tchad' },

  // --- ARGENT & TRAVAIL ---
  { id: '31', text: "L'argent est un bon serviteur mais un mauvais maître.", translation: "Money is a servant.", explanation: "Ne pas se laisser asservir par la richesse.", countryId: 'ZA', language: 'Zoulou', themeId: 'Argent & Travail', likesCount: 3100, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '32', text: "La sueur du travail est le parfum de la réussite.", translation: "Hard work smells like success.", explanation: "Le succès demande un effort honnête.", countryId: 'CI', language: 'Dioula', themeId: 'Argent & Travail', likesCount: 1600, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '33', text: "Si tu dors sur une natte empruntée, tu dors par terre.", translation: "Borrowed mats are floor.", explanation: "L'importance de l'indépendance financière.", countryId: 'BF', language: 'Mossi', themeId: 'Argent & Travail', likesCount: 580, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '34', text: "C'est au bout de la vieille corde qu'on tisse la nouvelle.", translation: "Build on old rope.", explanation: "Le travail se base sur l'expérience acquise.", countryId: 'CD', language: 'Lingala', themeId: 'Argent & Travail', likesCount: 940, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '35', text: "La fortune ne va pas chez celui qui dort.", translation: "Fortune avoids sleepers.", explanation: "Il faut être actif pour réussir.", countryId: 'UG', language: 'Luganda', themeId: 'Argent & Travail', likesCount: 720, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '36', text: "On ne mange pas la poule qui pond des œufs d'or.", translation: "Don't eat the golden hen.", explanation: "Savoir préserver ses sources de revenus.", countryId: 'EG', language: 'Arabe', themeId: 'Argent & Travail', likesCount: 1100, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Égypte' },

  // --- JUSTICE & VÉRITÉ ---
  { id: '37', text: "Le feu qui brûle la case n'épargne pas le toit.", translation: "Fire doesn't spare the roof.", explanation: "Les injustices finissent par toucher tout le monde.", countryId: 'SN', language: 'Wolof', themeId: 'Justice & Vérité', likesCount: 540, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '38', text: "Le mensonge produit des fleurs mais pas de fruits.", translation: "Lies bear no fruit.", explanation: "La tromperie ne mène à rien de durable.", countryId: 'ET', language: 'Amharique', themeId: 'Justice & Vérité', likesCount: 2700, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '39', text: "La vérité est comme le soleil, on ne peut la cacher.", translation: "Truth is like the sun.", explanation: "La vérité finit toujours par éclater au grand jour.", countryId: 'MA', language: 'Malagasy', themeId: 'Justice & Vérité', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Madagascar' },
  { id: '40', text: "On ne peut pas cacher la fumée si on a mis le feu.", translation: "Can't hide smoke from fire.", explanation: "On doit assumer les conséquences de ses actes.", countryId: 'ML', language: 'Bambara', themeId: 'Justice & Vérité', likesCount: 960, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '41', text: "La bouche qui mange ne parle pas de justice.", translation: "Eating mouths don't talk justice.", explanation: "Dénonciation de la corruption.", countryId: 'AO', language: 'Portugais', themeId: 'Justice & Vérité', likesCount: 310, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '42', text: "Mieux vaut une vérité qui fait mal qu'un mensonge qui réjouit.", translation: "Painful truth over sweet lie.", explanation: "L'intégrité avant tout.", countryId: 'BJ', language: 'Fon', themeId: 'Justice & Vérité', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '43', text: "Le juge qui n'écoute qu'une partie n'est pas juste.", translation: "Hear both sides.", explanation: "L'impartialité est la base de la justice.", countryId: 'SD', language: 'Arabe', themeId: 'Justice & Vérité', likesCount: 440, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Soudan' },
  { id: '44', text: "Si tu es dans le vrai, tu n'as pas besoin de crier.", translation: "Truth doesn't need shouting.", explanation: "La vérité a sa propre force tranquille.", countryId: 'MW', language: 'Chewa', themeId: 'Justice & Vérité', likesCount: 980, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Malawi' },

  // --- MIX COMPLÉMENTAIRE ---
  { id: '45', text: "Une main lave l'autre.", translation: "One hand washes the other.", explanation: "La réciprocité dans l'aide.", countryId: 'SN', language: 'Wolof', themeId: 'Famille & Communauté', likesCount: 1560, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '46', text: "Celui qui a été mordu par un serpent a peur d'un ver de terre.", translation: "Once bitten, twice shy.", explanation: "L'expérience nous rend plus prudents.", countryId: 'CD', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 880, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '47', text: "Même au milieu du fleuve, on a soif de vérité.", translation: "Thirst for truth.", explanation: "Le besoin fondamental d'honnêteté.", countryId: 'NG', language: 'Igbo', themeId: 'Justice & Vérité', likesCount: 520, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigéria' },
  { id: '48', text: "Le cœur d'une mère est un abri sûr.", translation: "Mother's heart is a shelter.", explanation: "L'amour inconditionnel maternel.", countryId: 'ML', language: 'Bambara', themeId: 'Famille & Communauté', likesCount: 2900, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '49', text: "On ne traverse pas le fleuve sur le dos d'un crocodile.", translation: "Don't ride the crocodile.", explanation: "Ne pas compter sur ses ennemis.", countryId: 'CG', language: 'Lingala', themeId: 'Courage & Persévérance', likesCount: 730, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '50', text: "Le temps est le remède à tous les maux.", translation: "Time heals all.", explanation: "La patience guérit la douleur.", countryId: 'BI', language: 'Kirundi', themeId: 'Sagesse & Patience', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burundi' },
  { id: '51', text: "Un arbre seul ne fait pas la forêt.", translation: "One tree alone does not make a forest.", explanation: "La communauté est essentielle à la vie sociale.", countryId: 'CI', language: 'Dioula', themeId: 'Communauté & Entraide', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '52', text: "La patience est la mère de toutes les vertus.", translation: "Patience is the mother of all virtues.", explanation: "Sans patience, aucune vertu ne peut s'épanouir.", countryId: 'MA', language: 'Darija', themeId: 'Sagesse & Patience', likesCount: 1450, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '53', text: "Celui qui creuse une fosse pour autrui y tombe le premier.", translation: "He who digs a pit for others falls in first.", explanation: "Le mal que l'on prépare aux autres nous revient.", countryId: 'SN', language: 'Wolof', themeId: 'Justice & Vérité', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '54', text: "Le soleil brille pour tout le monde, mais chacun reçoit sa part d'ombre.", translation: "The sun shines for everyone, but each receives their share of shadow.", explanation: "L'équité n'exclut pas les différences individuelles.", countryId: 'CM', language: 'Ewondo', themeId: 'Justice & Vérité', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '55', text: "Ce n'est pas parce que la nuit est longue qu'elle ne finit pas.", translation: "Just because the night is long doesn't mean it won't end.", explanation: "Tout moment difficile a une fin.", countryId: 'AO', language: 'Kimbundu', themeId: 'Espoir & Résilience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '56', text: "La bouche peut cacher la vérité, mais les yeux la révèlent toujours.", translation: "The mouth can hide the truth, but the eyes always reveal it.", explanation: "Le regard trahit ce que les mots tentent de dissimuler.", countryId: 'GH', language: 'Twi', themeId: 'Justice & Vérité', likesCount: 1410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '57', text: "On ne fait pas deux fois la même erreur si on est sage.", translation: "A wise person does not make the same mistake twice.", explanation: "La sagesse naît de l'apprentissage par l'expérience.", countryId: 'UG', language: 'Luganda', themeId: 'Sagesse & Patience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '58', text: "Le miel n'est pas fait pour la bouche de l'âne.", translation: "Honey is not made for the mouth of a donkey.", explanation: "Tout don précieux mérite un destinataire digne.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '59', text: "Ce que tu gardes pour toi-même te quitte ; ce que tu donnes aux autres reste.", translation: "What you keep for yourself leaves; what you give others remains.", explanation: "La générosité est la seule richesse qui perdure.", countryId: 'ET', language: 'Amharique', themeId: 'Générosité & Partage', likesCount: 1480, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '60', text: "Le chasseur qui chasse deux lièvres à la fois n'en attrape aucun.", translation: "The hunter who chases two hares at once catches none.", explanation: "La dispersion de l'attention mène à l'échec.", countryId: 'ZM', language: 'Bemba', themeId: 'Travail & Persévérance', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '61', text: "L'enfant qui n'est pas aimé devient le crocodile du village.", translation: "The unloved child becomes the village's crocodile.", explanation: "Le manque d'amour dans l'enfance engendre la violence.", countryId: 'GN', language: 'Peul', themeId: 'Famille & Éducation', likesCount: 1390, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '62', text: "Nul ne sait ce qui est dans le ventre d'une calebasse fermée.", translation: "No one knows what is inside a closed calabash.", explanation: "Les apparences ne révèlent pas la vérité intérieure.", countryId: 'BJ', language: 'Fon', themeId: 'Sagesse & Patience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '63', text: "La nuit porte conseil, mais le matin donne la décision.", translation: "The night brings counsel, but the morning brings the decision.", explanation: "Réfléchir avant d'agir conduit à de meilleures décisions.", countryId: 'CD', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '64', text: "Une femme, c'est la terre : elle nourrit, elle accueille, elle dure.", translation: "A woman is the earth: she nourishes, welcomes, and endures.", explanation: "La femme est le fondement de la vie et de la société.", countryId: 'SN', language: 'Wolof', themeId: 'Famille & Éducation', likesCount: 1520, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '65', text: "L'autorité du chef se mesure au silence de ses sujets.", translation: "The authority of a leader is measured by the silence of his subjects.", explanation: "Un vrai leader inspire le respect sans imposer la peur.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Leadership & Pouvoir', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '66', text: "Quand l'éléphant marche, le sol tremble pour tout le monde.", translation: "When the elephant walks, the ground trembles for everyone.", explanation: "Les actions des puissants ont des répercussions sur tous.", countryId: 'CM', language: 'Bamiléké', themeId: 'Leadership & Pouvoir', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '67', text: "Celui qui n'a jamais voyagé croit que sa mère est la meilleure cuisinière.", translation: "He who has never traveled thinks his mother is the best cook.", explanation: "Le voyage élargit les horizons et remet en question nos certitudes.", countryId: 'TG', language: 'Éwé', themeId: 'Sagesse & Patience', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '68', text: "Le cœur de l'homme est un tambour qu'on n'entend que quand il bat fort.", translation: "The heart of man is a drum only heard when it beats loudly.", explanation: "Les émotions profondes ne se révèlent qu'en temps de crise.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '69', text: "Les problèmes de la poule ne sont pas ceux du coq.", translation: "The hen's problems are not the rooster's problems.", explanation: "Chacun a ses propres épreuves que les autres ne perçoivent pas.", countryId: 'NG', language: 'Yoruba', themeId: 'Sagesse & Patience', likesCount: 1300, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '70', text: "Mieux vaut un voisin proche qu'un frère lointain.", translation: "Better a close neighbor than a distant brother.", explanation: "La proximité crée des liens parfois plus solides que le sang.", countryId: 'MA', language: 'Darija', themeId: 'Communauté & Entraide', likesCount: 1430, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '71', text: "Qui se lève tôt mange la rosée du matin.", translation: "He who rises early eats the morning dew.", explanation: "L'effort et la ponctualité sont récompensés.", countryId: 'BF', language: 'Mooré', themeId: 'Travail & Persévérance', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '72', text: "L'âge du palmier ne se lit pas à la hauteur de ses branches.", translation: "The age of a palm tree is not read by the height of its branches.", explanation: "L'apparence ne révèle pas toujours la sagesse ou l'expérience.", countryId: 'CI', language: 'Dioula', themeId: 'Sagesse & Patience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '73', text: "La vérité est comme l'huile dans l'eau : elle finit toujours par remonter.", translation: "Truth is like oil in water: it always rises to the top.", explanation: "La vérité ne peut rester cachée indéfiniment.", countryId: 'CG', language: 'Lingala', themeId: 'Justice & Vérité', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '74', text: "Celui qui porte un habit sale ne voit que la saleté des autres.", translation: "He who wears dirty clothes sees only the dirt of others.", explanation: "Nos propres défauts nous rendent aveugles à nos propres torts.", countryId: 'KE', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '75', text: "La faim et la sagesse ne cohabitent jamais longtemps.", translation: "Hunger and wisdom never coexist for long.", explanation: "Les besoins primaires doivent être satisfaits pour que l'esprit s'élève.", countryId: 'TZ', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '76', text: "Si l'escargot avait su, il ne serait pas sorti sous la pluie.", translation: "If the snail had known, it would not have come out in the rain.", explanation: "L'anticipation permet d'éviter bien des malheurs.", countryId: 'CI', language: 'Dioula', themeId: 'Sagesse & Patience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '77', text: "Le forgeron qui n'a pas de cicatrices n'a pas vraiment travaillé.", translation: "A blacksmith without scars has not truly worked.", explanation: "Le vrai travail laisse des traces et forge le caractère.", countryId: 'ML', language: 'Bambara', themeId: 'Travail & Persévérance', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '78', text: "Ce que la rivière ignore, l'océan le sait.", translation: "What the river does not know, the ocean knows.", explanation: "La sagesse croît avec l'expérience et la profondeur.", countryId: 'MZ', language: 'Makua', themeId: 'Sagesse & Patience', likesCount: 1180, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '79', text: "L'enfant qui demande ne sera jamais perdu.", translation: "The child who asks will never be lost.", explanation: "Poser des questions est le chemin vers la connaissance.", countryId: 'CD', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '80', text: "La langue n'a pas d'os, mais elle peut briser des os.", translation: "The tongue has no bones, but it can break bones.", explanation: "Les mots peuvent causer des blessures profondes.", countryId: 'SN', language: 'Wolof', themeId: 'Justice & Vérité', likesCount: 1490, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '81', text: "Un seul doigt ne peut ramasser un grain de sable.", translation: "A single finger cannot pick up a grain of sand.", explanation: "L'union des forces est indispensable pour accomplir les tâches.", countryId: 'GN', language: 'Peul', themeId: 'Communauté & Entraide', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '82', text: "La peur du léopard ne fait pas reculer la nuit.", translation: "Fear of the leopard does not push back the night.", explanation: "La peur ne change pas la réalité ; il faut y faire face.", countryId: 'GA', language: 'Fang', themeId: 'Espoir & Résilience', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '83', text: "Le vent se souvient de chaque arbre qu'il a renversé.", translation: "The wind remembers every tree it has knocked down.", explanation: "Nos actions laissent des traces que nous ne pouvons effacer.", countryId: 'ET', language: 'Amharique', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '84', text: "Ne mange pas ton grain de semence sous peine de ne rien récolter.", translation: "Do not eat your seed grain or you will have nothing to harvest.", explanation: "Il faut savoir investir aujourd'hui pour récolter demain.", countryId: 'GH', language: 'Twi', themeId: 'Travail & Persévérance', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '85', text: "La pluie ne sait pas qu'elle noie le fourmilier.", translation: "The rain does not know it is drowning the anthill.", explanation: "L'ignorance des conséquences n'efface pas la responsabilité.", countryId: 'NG', language: 'Igbo', themeId: 'Sagesse & Patience', likesCount: 1170, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '86', text: "Même le plus grand voyage commence par un seul pas.", translation: "Even the longest journey begins with a single step.", explanation: "Toute grande entreprise débute par une petite action.", countryId: 'UG', language: 'Luganda', themeId: 'Travail & Persévérance', likesCount: 1440, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '87', text: "L'homme n'est pas une houe qu'on abandonne quand il est usé.", translation: "A man is not a hoe to be discarded when worn out.", explanation: "La dignité humaine ne diminue pas avec l'âge ou la faiblesse.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Justice & Vérité', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '88', text: "Autant vaut l'ombre d'un arbre que celle de ton ami.", translation: "The shade of a tree is worth as much as that of your friend.", explanation: "Un véritable ami apporte réconfort et protection.", countryId: 'MA', language: 'Darija', themeId: 'Amitié & Relations', likesCount: 1300, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '89', text: "Quand la musique change, les pas de danse doivent changer aussi.", translation: "When the music changes, the dance steps must change too.", explanation: "S'adapter aux nouvelles situations est une marque de sagesse.", countryId: 'ZM', language: 'Nyanja', themeId: 'Sagesse & Patience', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '90', text: "Un homme sans culture est comme une plante sans racines.", translation: "A man without culture is like a plant without roots.", explanation: "La culture et l'identité sont les fondements de l'être.", countryId: 'ZA', language: 'Zulu', themeId: 'Identité & Héritage', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '91', text: "La jalousie est un ver qui ronge de l'intérieur sans se voir.", translation: "Jealousy is a worm that gnaws from within without being seen.", explanation: "La jalousie détruit celui qui la ressent sans qu'il s'en aperçoive.", countryId: 'CM', language: 'Bamiléké', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '92', text: "Là où il y a de la fumée, il y a eu du feu.", translation: "Where there is smoke, there has been fire.", explanation: "Tout effet a une cause ; les signes ne mentent pas.", countryId: 'BJ', language: 'Fon', themeId: 'Justice & Vérité', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '93', text: "L'homme qui ne connaît pas ses ancêtres est comme un arbre sans racines.", translation: "A man who does not know his ancestors is like a tree without roots.", explanation: "Connaître ses origines est essentiel à la construction de soi.", countryId: 'ZW', language: 'Shona', themeId: 'Identité & Héritage', likesCount: 1410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '94', text: "Le silence est la réponse du sage à la question du fou.", translation: "Silence is the wise man's answer to a fool's question.", explanation: "Savoir se taire face à la provocation est une forme de sagesse.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1470, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '95', text: "Personne ne sait qui a creusé le puits dont il boit.", translation: "No one knows who dug the well from which they drink.", explanation: "Il faut être reconnaissant envers ceux dont on ignore les sacrifices.", countryId: 'ML', language: 'Bambara', themeId: 'Générosité & Partage', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '96', text: "Chaque matin est une nouvelle chance de bien faire.", translation: "Every morning is a new chance to do good.", explanation: "Chaque jour offre l'opportunité de recommencer et de s'améliorer.", countryId: 'TG', language: 'Éwé', themeId: 'Espoir & Résilience', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '97', text: "La fierté du lion ne lui permet pas de fuir la pluie.", translation: "The lion's pride does not allow it to flee from the rain.", explanation: "La dignité impose d'affronter les épreuves sans se dérober.", countryId: 'KE', language: 'Swahili', themeId: 'Espoir & Résilience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '98', text: "L'enfant qui grandit sans correction devient le bourreau de ses parents.", translation: "A child raised without discipline becomes the tormentor of their parents.", explanation: "L'éducation bienveillante protège l'enfant et sa famille.", countryId: 'CG', language: 'Kituba', themeId: 'Famille & Éducation', likesCount: 1310, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '99', text: "Il faut regarder derrière soi pour bien avancer en avant.", translation: "One must look behind to move forward well.", explanation: "Le passé éclaire le chemin vers l'avenir.", countryId: 'SN', language: 'Wolof', themeId: 'Identité & Héritage', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '100', text: "Même la flèche la plus rapide ne revient pas en arrière.", translation: "Even the fastest arrow does not come back.", explanation: "Certaines actions et paroles sont irréversibles.", countryId: 'TZ', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '101', text: "Qui garde un secret est maître de lui-même.", translation: "He who keeps a secret is master of himself.", explanation: "La discrétion est une forme de maîtrise de soi et de pouvoir.", countryId: 'MA', language: 'Darija', themeId: 'Sagesse & Patience', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '102', text: "Le paresseux fait toujours son travail deux fois.", translation: "The lazy person always does their work twice.", explanation: "Négliger ses tâches oblige à les recommencer.", countryId: 'ET', language: 'Amharique', themeId: 'Travail & Persévérance', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '103', text: "L'éléphant ne sait pas le poids de ses propres défenses.", translation: "The elephant does not know the weight of its own tusks.", explanation: "On ignore souvent le fardeau que l'on représente pour les autres.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '104', text: "La rivière qui fait du bruit n'est pas toujours la plus profonde.", translation: "The noisy river is not always the deepest.", explanation: "Les apparences trompeuses cachent souvent la réalité.", countryId: 'CI', language: 'Dioula', themeId: 'Sagesse & Patience', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '105', text: "Un couteau seul ne peut pas se tailler lui-même.", translation: "A knife alone cannot sharpen itself.", explanation: "Nous avons tous besoin des autres pour progresser.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Communauté & Entraide', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '106', text: "Enseigne à tes enfants ce que tu as appris dans la douleur.", translation: "Teach your children what you learned through pain.", explanation: "Transmettre ses expériences difficiles préserve les générations futures.", countryId: 'UG', language: 'Luganda', themeId: 'Famille & Éducation', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '107', text: "Le destin donne les occasions, l'homme doit les saisir.", translation: "Destiny provides the opportunities; man must seize them.", explanation: "La chance seule ne suffit pas sans l'initiative personnelle.", countryId: 'BF', language: 'Mooré', themeId: 'Travail & Persévérance', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '108', text: "La maison du mensonge est petite mais le mensonge y reste longtemps.", translation: "The house of lies is small but the lie stays there a long time.", explanation: "Le mensonge s'installe facilement mais ses effets durent.", countryId: 'NG', language: 'Hausa', themeId: 'Justice & Vérité', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '109', text: "Un peuple sans histoire est un peuple sans âme.", translation: "A people without history is a people without a soul.", explanation: "L'histoire collective est l'identité d'une nation.", countryId: 'ZA', language: 'Zulu', themeId: 'Identité & Héritage', likesCount: 1450, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '110', text: "La vraie beauté est celle du cœur, pas celle du visage.", translation: "True beauty is that of the heart, not of the face.", explanation: "La bonté intérieure surpasse la beauté physique.", countryId: 'GH', language: 'Twi', themeId: 'Sagesse & Patience', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '111', text: "Même la lune connaît ses jours d'obscurité.", translation: "Even the moon knows its days of darkness.", explanation: "Tout être, même le plus brillant, traverse des moments difficiles.", countryId: 'AO', language: 'Kimbundu', themeId: 'Espoir & Résilience', likesCount: 1300, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '112', text: "Le tigre ne proclame pas sa férocité.", translation: "The tiger does not proclaim its ferocity.", explanation: "La vraie force n'a pas besoin d'être annoncée.", countryId: 'CM', language: 'Ewondo', themeId: 'Sagesse & Patience', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '113', text: "Ce que la tortue fait lentement, elle le fait sûrement.", translation: "What the tortoise does slowly, it does surely.", explanation: "La lenteur et la constance mènent à des résultats solides.", countryId: 'ML', language: 'Bambara', themeId: 'Travail & Persévérance', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '114', text: "Si tu parles à l'oreille d'une calebasse, la calebasse parle au village.", translation: "If you speak into a calabash's ear, the calabash speaks to the village.", explanation: "Rien n'est vraiment secret ; les confidences finissent par se savoir.", countryId: 'BJ', language: 'Fon', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '115', text: "L'oiseau qui ne vole qu'en beau temps ne connaît pas le vrai ciel.", translation: "The bird that only flies in fair weather does not know the true sky.", explanation: "L'adversité révèle la vraie nature et la vraie force.", countryId: 'CD', language: 'Lingala', themeId: 'Espoir & Résilience', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '116', text: "On ne réveille pas un lion qui dort si on n'est pas prêt à courir.", translation: "Do not wake a sleeping lion if you are not ready to run.", explanation: "Il ne faut pas provoquer des forces dont on ne peut contrôler les réactions.", countryId: 'KE', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '117', text: "Le temps guérit les blessures du corps, mais pas toujours celles de l'âme.", translation: "Time heals the wounds of the body, but not always those of the soul.", explanation: "Certaines souffrances intérieures nécessitent plus que le simple passage du temps.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '118', text: "La vérité se dit mieux autour d'un feu à la tombée de la nuit.", translation: "Truth is best spoken around a fire at nightfall.", explanation: "La chaleur du partage facilite les confidences sincères.", countryId: 'ZW', language: 'Shona', themeId: 'Justice & Vérité', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '119', text: "Quand les anciens meurent, les jeunes naissent pour les remplacer.", translation: "When the elders die, the young are born to replace them.", explanation: "La vie est un cycle continu de transmission et de renouveau.", countryId: 'GN', language: 'Peul', themeId: 'Identité & Héritage', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '120', text: "Le champ d'un homme vaillant ne reste jamais en friche.", translation: "The field of a brave man never lies fallow.", explanation: "Le courage et l'ardeur au travail garantissent la prospérité.", countryId: 'ZM', language: 'Bemba', themeId: 'Travail & Persévérance', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '121', text: "Le chameau ne voit pas sa propre bosse.", translation: "The camel does not see its own hump.", explanation: "Nous sommes souvent aveugles à nos propres défauts.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '122', text: "La lumière du feu de camp est plus belle quand on est ensemble.", translation: "The light of a campfire is more beautiful when shared together.", explanation: "La communauté enrichit chaque expérience de vie.", countryId: 'TZ', language: 'Swahili', themeId: 'Communauté & Entraide', likesCount: 1430, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '123', text: "Un homme qui ne respecte pas sa femme ne respecte pas sa mère.", translation: "A man who does not respect his wife does not respect his mother.", explanation: "Le respect dû aux femmes est universel et fondamental.", countryId: 'TG', language: 'Éwé', themeId: 'Famille & Éducation', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '124', text: "Le forgeron forge dans la chaleur, pas dans le confort.", translation: "The blacksmith forges in heat, not in comfort.", explanation: "Les grandes réalisations naissent de l'effort et de la persévérance.", countryId: 'BF', language: 'Mooré', themeId: 'Travail & Persévérance', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '125', text: "Celui qui attend le moment parfait n'agit jamais.", translation: "He who waits for the perfect moment never acts.", explanation: "Attendre les conditions idéales conduit à l'inaction perpétuelle.", countryId: 'GA', language: 'Fang', themeId: 'Travail & Persévérance', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '126', text: "L'arc-en-ciel ne montre ses couleurs qu'après la pluie.", translation: "The rainbow only shows its colors after the rain.", explanation: "Les moments difficiles précèdent souvent de belles récompenses.", countryId: 'MZ', language: 'Makua', themeId: 'Espoir & Résilience', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '127', text: "La main droite lave la gauche, et ensemble elles se lavent le visage.", translation: "The right hand washes the left, and together they wash the face.", explanation: "La coopération mutuelle accomplit ce que l'effort solitaire ne peut faire.", countryId: 'ET', language: 'Amharique', themeId: 'Communauté & Entraide', likesCount: 1480, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '128', text: "Un enfant qui respecte les anciens hérite de leur sagesse.", translation: "A child who respects elders inherits their wisdom.", explanation: "Le respect des aînés est le moyen d'accéder à leur expérience.", countryId: 'CG', language: 'Kituba', themeId: 'Identité & Héritage', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '129', text: "Le chasseur courageux ramène toujours quelque chose, même si c'est peu.", translation: "The courageous hunter always brings back something, even if it is little.", explanation: "L'effort et la détermination produisent toujours un résultat.", countryId: 'NG', language: 'Yoruba', themeId: 'Travail & Persévérance', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '130', text: "La lune n'est pas jalouse du soleil parce qu'elle brille la nuit.", translation: "The moon is not jealous of the sun because it shines at night.", explanation: "Chacun a sa propre place et son propre moment de briller.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Sagesse & Patience', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '131', text: "L'homme sage construit sa maison avec la patience, pas avec la hâte.", translation: "The wise man builds his house with patience, not haste.", explanation: "La précipitation compromet la qualité et la solidité de ce que l'on construit.", countryId: 'CM', language: 'Ewondo', themeId: 'Sagesse & Patience', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '132', text: "Quand on parle de loup, on en voit la queue.", translation: "When you speak of the wolf, you see its tail.", explanation: "Parler de quelqu'un le fait souvent apparaître.", countryId: 'MA', language: 'Darija', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '133', text: "Qui sème le vent récolte la tempête.", translation: "He who sows the wind reaps the storm.", explanation: "Les actions irresponsables engendrent des conséquences désastreuses.", countryId: 'CI', language: 'Dioula', themeId: 'Justice & Vérité', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '134', text: "La vie est comme une danse : il faut savoir s'adapter au rythme.", translation: "Life is like a dance: one must know how to adapt to the rhythm.", explanation: "La flexibilité et l'adaptation sont essentielles pour traverser la vie.", countryId: 'GH', language: 'Twi', themeId: 'Sagesse & Patience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '135', text: "L'amour d'une mère est le seul amour qui ne demande rien en retour.", translation: "A mother's love is the only love that asks nothing in return.", explanation: "L'amour maternel est le symbole de la générosité absolue.", countryId: 'UG', language: 'Luganda', themeId: 'Famille & Éducation', likesCount: 1550, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '136', text: "Celui qui connaît son chemin n'a pas besoin de guide.", translation: "He who knows his path needs no guide.", explanation: "La connaissance de soi et de ses objectifs rend autonome.", countryId: 'TZ', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '137', text: "La vache ne pleure pas pour son propre lait.", translation: "The cow does not cry for its own milk.", explanation: "La vraie générosité donne sans regret ni calcul.", countryId: 'ML', language: 'Bambara', themeId: 'Générosité & Partage', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '138', text: "Un village sans vieillard est une ville sans lumière.", translation: "A village without an elder is a town without light.", explanation: "Les anciens sont les gardiens de la sagesse et de la mémoire collective.", countryId: 'SN', language: 'Wolof', themeId: 'Identité & Héritage', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '139', text: "Le courage d'un lion ne sert à rien sans l'intelligence.", translation: "The courage of a lion is useless without intelligence.", explanation: "La force doit toujours être guidée par la sagesse.", countryId: 'ZM', language: 'Bemba', themeId: 'Sagesse & Patience', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '140', text: "La main qui donne est plus forte que celle qui prend.", translation: "The hand that gives is stronger than the one that takes.", explanation: "La générosité est une forme de puissance et de noblesse.", countryId: 'BJ', language: 'Fon', themeId: 'Générosité & Partage', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '141', text: "L'eau ne se souvient pas de la forme du vase qu'elle a rempli.", translation: "Water does not remember the shape of the vessel it filled.", explanation: "La liberté retrouvée efface les contraintes passées.", countryId: 'AO', language: 'Kimbundu', themeId: 'Espoir & Résilience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '142', text: "Ce qui est appris en bas âge est gravé dans le marbre.", translation: "What is learned in childhood is carved in marble.", explanation: "L'éducation précoce laisse des empreintes durables.", countryId: 'DZ', language: 'Tamazight', themeId: 'Famille & Éducation', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '143', text: "Le forgeron ne peut forger que ce qu'il voit.", translation: "The blacksmith can only forge what he sees.", explanation: "La connaissance et la vision sont les conditions de toute création.", countryId: 'ZW', language: 'Shona', themeId: 'Sagesse & Patience', likesCount: 1180, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '144', text: "La patience est un arbre aux racines amères mais aux fruits doux.", translation: "Patience is a tree with bitter roots but sweet fruits.", explanation: "Supporter l'attente difficile mène à de belles récompenses.", countryId: 'NG', language: 'Hausa', themeId: 'Sagesse & Patience', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '145', text: "Celui qui refuse d'apprendre est condamné à vivre dans l'ignorance.", translation: "He who refuses to learn is condemned to live in ignorance.", explanation: "Fermer son esprit à la connaissance est s'enfermer dans l'obscurité.", countryId: 'KE', language: 'Swahili', themeId: 'Famille & Éducation', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '146', text: "Le mensonge court vite, mais la vérité le rattrape toujours.", translation: "A lie runs fast, but the truth always catches up.", explanation: "La vérité finit toujours par triompher du mensonge.", countryId: 'GA', language: 'Fang', themeId: 'Justice & Vérité', likesCount: 1440, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '147', text: "La fierté mal placée est la mère de l'humiliation.", translation: "Misplaced pride is the mother of humiliation.", explanation: "L'orgueil excessif prépare la honte.", countryId: 'CD', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '148', text: "Si la parole ne vaut rien, ne parle pas.", translation: "If words are worth nothing, do not speak.", explanation: "Mieux vaut le silence que des paroles vides de sens.", countryId: 'TG', language: 'Éwé', themeId: 'Sagesse & Patience', likesCount: 1180, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '149', text: "L'oiseau ne blâme pas la forêt parce qu'elle est grande.", translation: "The bird does not blame the forest for being large.", explanation: "Il faut accepter le monde tel qu'il est avec humilité.", countryId: 'ET', language: 'Amharique', themeId: 'Sagesse & Patience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '150', text: "La pluie qui tombe doucement pénètre la terre plus profondément.", translation: "Rain that falls gently soaks deeper into the earth.", explanation: "La douceur et la constance ont souvent plus d'effet que la force brute.", countryId: 'BF', language: 'Mooré', themeId: 'Sagesse & Patience', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '151', text: "Ce que les yeux voient, le cœur ne peut l'oublier.", translation: "What the eyes see, the heart cannot forget.", explanation: "Les expériences vécues marquent profondément la mémoire.", countryId: 'CM', language: 'Bamiléké', themeId: 'Sagesse & Patience', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '152', text: "L'homme qui court après deux lapins n'attrape aucun.", translation: "The man who chases two rabbits catches none.", explanation: "La dispersion des efforts conduit à l'échec.", countryId: 'MZ', language: 'Makua', themeId: 'Travail & Persévérance', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '153', text: "Le feu qui brûle à l'intérieur est plus dangereux que celui du dehors.", translation: "The fire that burns inside is more dangerous than the one outside.", explanation: "Les conflits intérieurs et les émotions non gérées sont les plus destructeurs.", countryId: 'GN', language: 'Peul', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '154', text: "Une journée sans apprendre quelque chose est une journée perdue.", translation: "A day without learning something is a lost day.", explanation: "L'apprentissage quotidien est la clé d'une vie épanouie.", countryId: 'MA', language: 'Darija', themeId: 'Famille & Éducation', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '155', text: "Le destin de l'oiseau est dans ses ailes, pas dans sa cage.", translation: "The fate of the bird lies in its wings, not in its cage.", explanation: "La liberté est la condition naturelle de tout être vivant.", countryId: 'ZA', language: 'Zulu', themeId: 'Espoir & Résilience', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '156', text: "Quand un aveugle dit qu'il voit, il ment à lui-même.", translation: "When a blind man says he sees, he lies to himself.", explanation: "Se mentir à soi-même est la pire des tromperies.", countryId: 'CG', language: 'Kituba', themeId: 'Justice & Vérité', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '157', text: "L'homme sage écoute plus qu'il ne parle.", translation: "The wise man listens more than he speaks.", explanation: "L'écoute attentive est le fondement de la sagesse.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '158', text: "Le tambour qui crie trop fort finit par se faire briser.", translation: "The drum that cries too loudly ends up being broken.", explanation: "L'excès de bruit ou d'arrogance attire la destruction.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Sagesse & Patience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '159', text: "Un peuple uni est invincible comme le rocher dans la mer.", translation: "A united people is invincible like a rock in the sea.", explanation: "L'union confère une force que rien ne peut briser.", countryId: 'GH', language: 'Twi', themeId: 'Communauté & Entraide', likesCount: 1490, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '160', text: "La chaîne est aussi forte que son maillon le plus faible.", translation: "A chain is only as strong as its weakest link.", explanation: "La solidité d'un groupe dépend de chacun de ses membres.", countryId: 'TZ', language: 'Swahili', themeId: 'Communauté & Entraide', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '161', text: "Ce que tu n'as pas appris jeune, tu l'apprends vieux et avec douleur.", translation: "What you did not learn young, you learn old and with pain.", explanation: "Les leçons tardives coûtent bien plus cher.", countryId: 'ML', language: 'Bambara', themeId: 'Famille & Éducation', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '162', text: "Le coq ne chante jamais deux fois de la même façon.", translation: "The rooster never crows twice in the same way.", explanation: "Chaque moment est unique et ne se répète jamais.", countryId: 'NG', language: 'Igbo', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '163', text: "La main tendue reçoit toujours plus que la main fermée.", translation: "The outstretched hand always receives more than the closed one.", explanation: "L'ouverture et la générosité attirent l'abondance.", countryId: 'KE', language: 'Swahili', themeId: 'Générosité & Partage', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '164', text: "Un seul arbre ne peut arrêter la tempête, mais la forêt si.", translation: "One tree alone cannot stop the storm, but the forest can.", explanation: "L'union des forces individuelles crée une protection collective.", countryId: 'ZM', language: 'Nyanja', themeId: 'Communauté & Entraide', likesCount: 1410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '165', text: "L'écho répond toujours à celui qui crie dans la montagne.", translation: "The echo always answers the one who shouts in the mountain.", explanation: "Nos actions et nos paroles nous reviennent toujours.", countryId: 'ET', language: 'Amharique', themeId: 'Justice & Vérité', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '166', text: "La forêt n'a pas de secrets pour celui qui l'écoute.", translation: "The forest has no secrets for the one who listens to it.", explanation: "La nature révèle sa sagesse à ceux qui savent observer et écouter.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '167', text: "Le roi est un roi grâce à son peuple.", translation: "A king is a king because of his people.", explanation: "Toute autorité tire sa légitimité de ceux qu'elle gouverne.", countryId: 'ZW', language: 'Shona', themeId: 'Leadership & Pouvoir', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '168', text: "Ne vends pas la peau de l'ours avant de l'avoir chassé.", translation: "Do not sell the bear's skin before having hunted it.", explanation: "Il ne faut pas compter sur ce qu'on ne possède pas encore.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '169', text: "La sagesse est un bagage qu'aucun voleur ne peut prendre.", translation: "Wisdom is a baggage no thief can take.", explanation: "La sagesse acquise est la seule richesse véritablement inaltérable.", countryId: 'CI', language: 'Dioula', themeId: 'Sagesse & Patience', likesCount: 1430, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '170', text: "La bougie qui éclaire les autres se consume elle-même.", translation: "The candle that lights others consumes itself.", explanation: "Le sacrifice de soi pour les autres est une forme de grandeur.", countryId: 'TG', language: 'Éwé', themeId: 'Générosité & Partage', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '171', text: "Quand les anciens parlent, les jeunes doivent écouter des deux oreilles.", translation: "When elders speak, the young must listen with both ears.", explanation: "La sagesse des anciens mérite une attention totale et respectueuse.", countryId: 'UG', language: 'Luganda', themeId: 'Identité & Héritage', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '172', text: "L'homme qui ne fait rien ne fait pas d'erreurs, mais il ne grandit pas.", translation: "The man who does nothing makes no mistakes, but he does not grow.", explanation: "L'inaction préserve de l'échec mais empêche tout progrès.", countryId: 'BJ', language: 'Fon', themeId: 'Travail & Persévérance', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '173', text: "Le vent qui souffle fort n'est pas celui qui porte le plus loin.", translation: "The wind that blows hard is not the one that carries the farthest.", explanation: "La puissance brute n'est pas toujours la plus efficace.", countryId: 'CG', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '174', text: "La richesse d'un homme se mesure à ce qu'il donne, pas à ce qu'il possède.", translation: "A man's wealth is measured by what he gives, not what he owns.", explanation: "La vraie richesse est dans la générosité, non dans l'accumulation.", countryId: 'CD', language: 'Lingala', themeId: 'Générosité & Partage', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '175', text: "Un enfant ne naît pas mauvais : c'est la société qui le forme.", translation: "A child is not born bad: it is society that shapes them.", explanation: "L'environnement social est déterminant dans le développement moral.", countryId: 'CM', language: 'Ewondo', themeId: 'Famille & Éducation', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '176', text: "Le lion vieux est respecté même quand il ne rugit plus.", translation: "The old lion is respected even when it no longer roars.", explanation: "La sagesse et l'expérience commandent le respect au-delà de la force.", countryId: 'SN', language: 'Wolof', themeId: 'Identité & Héritage', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '177', text: "Celui qui prend la route de nuit doit connaître les étoiles.", translation: "He who takes the road at night must know the stars.", explanation: "Toute entreprise difficile exige une bonne préparation.", countryId: 'MA', language: 'Darija', themeId: 'Sagesse & Patience', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '178', text: "La rivière n'a jamais honte de ses méandres.", translation: "The river is never ashamed of its meanders.", explanation: "Les détours de la vie font partie du chemin et ne sont pas une honte.", countryId: 'AO', language: 'Kimbundu', themeId: 'Sagesse & Patience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '179', text: "On ne plante pas du maïs pour voir pousser des ignames.", translation: "You do not plant corn expecting yams to grow.", explanation: "Les résultats correspondent toujours aux efforts et aux intentions.", countryId: 'GH', language: 'Twi', themeId: 'Justice & Vérité', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '180', text: "L'oiseau emprisonné chante pour rappeler qu'il est libre à l'intérieur.", translation: "The imprisoned bird sings to remind itself it is free inside.", explanation: "La liberté intérieure résiste à toute contrainte extérieure.", countryId: 'BF', language: 'Mooré', themeId: 'Espoir & Résilience', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '181', text: "Le fruit tombe toujours au pied de l'arbre.", translation: "The fruit always falls at the foot of the tree.", explanation: "Les enfants héritent souvent du caractère et des valeurs de leurs parents.", countryId: 'MZ', language: 'Makua', themeId: 'Famille & Éducation', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '182', text: "Si tu veux connaître quelqu'un, voyages avec lui.", translation: "If you want to know someone, travel with them.", explanation: "Le voyage révèle la vraie nature des personnes.", countryId: 'ML', language: 'Bambara', themeId: 'Amitié & Relations', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '183', text: "Là où il n'y a pas d'hommes, tâche de l'être.", translation: "Where there are no men, strive to be one.", explanation: "Face à l'absence de leaders, chacun doit prendre ses responsabilités.", countryId: 'ZA', language: 'Zulu', themeId: 'Leadership & Pouvoir', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '184', text: "La paix est plus précieuse que l'abondance.", translation: "Peace is more precious than abundance.", explanation: "La tranquillité de l'âme vaut plus que toutes les richesses matérielles.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Espoir & Résilience', likesCount: 1500, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '185', text: "Ce n'est pas la taille du bâton qui arrête le lion, c'est la confiance.", translation: "It is not the size of the stick that stops the lion, it is confidence.", explanation: "La confiance en soi est une arme plus puissante que la force physique.", countryId: 'NG', language: 'Yoruba', themeId: 'Espoir & Résilience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '186', text: "L'enfant qui ne connaît pas son père est un arbre sans racines.", translation: "A child who does not know his father is a tree without roots.", explanation: "L'identité familiale est fondamentale à la construction de soi.", countryId: 'KE', language: 'Swahili', themeId: 'Identité & Héritage', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '187', text: "La peur du danger est mille fois plus douloureuse que le danger lui-même.", translation: "Fear of danger is a thousand times more painful than the danger itself.", explanation: "L'anxiété anticipatoire est souvent pire que la réalité.", countryId: 'TZ', language: 'Swahili', themeId: 'Espoir & Résilience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '188', text: "Le cœur d'une mère est l'école la plus complète.", translation: "A mother's heart is the most complete school.", explanation: "L'amour et la sagesse maternelle forment le socle de toute éducation.", countryId: 'GN', language: 'Peul', themeId: 'Famille & Éducation', likesCount: 1480, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '189', text: "Qui garde la forêt garde l'avenir.", translation: "He who protects the forest protects the future.", explanation: "La préservation de la nature est une responsabilité envers les générations futures.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '190', text: "La loi du plus fort n'est jamais la loi du plus sage.", translation: "The law of the strongest is never the law of the wisest.", explanation: "La force brute ne confère pas la sagesse ni la légitimité.", countryId: 'CG', language: 'Kituba', themeId: 'Justice & Vérité', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '191', text: "Un espoir vivant vaut mieux que cent rêves morts.", translation: "A living hope is worth more than a hundred dead dreams.", explanation: "Mieux vaut un seul espoir actif que de nombreuses illusions abandonnées.", countryId: 'ET', language: 'Amharique', themeId: 'Espoir & Résilience', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '192', text: "L'homme sage connaît ses limites et les respecte.", translation: "The wise man knows his limits and respects them.", explanation: "La connaissance de soi passe par l'acceptation de ses propres limites.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '193', text: "Ce que la bouche dit, les mains doivent le faire.", translation: "What the mouth says, the hands must do.", explanation: "L'intégrité exige que les paroles soient suivies d'actes.", countryId: 'ZM', language: 'Bemba', themeId: 'Justice & Vérité', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '194', text: "Les pieds de l'homme suivent son cœur.", translation: "A man's feet follow his heart.", explanation: "Nos actions sont guidées par nos désirs et nos valeurs profondes.", countryId: 'BJ', language: 'Fon', themeId: 'Sagesse & Patience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '195', text: "L'injustice commise contre un seul est une menace pour tous.", translation: "An injustice against one is a threat to all.", explanation: "L'injustice individuelle met en danger le tissu social tout entier.", countryId: 'ZW', language: 'Shona', themeId: 'Justice & Vérité', likesCount: 1440, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '196', text: "La vérité peut blesser, mais le mensonge tue.", translation: "The truth may wound, but the lie kills.", explanation: "Malgré sa dureté, la vérité protège, alors que le mensonge détruit.", countryId: 'CM', language: 'Ewondo', themeId: 'Justice & Vérité', likesCount: 1470, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '197', text: "Un homme sans parole est comme un outil sans tranchant.", translation: "A man without his word is like a tool without an edge.", explanation: "L'honneur d'un homme repose sur la valeur de sa parole.", countryId: 'TG', language: 'Éwé', themeId: 'Justice & Vérité', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '198', text: "La connaissance du chemin ne vaut rien si on ne marche pas.", translation: "Knowing the path is worthless if you do not walk it.", explanation: "Le savoir sans action reste stérile.", countryId: 'UG', language: 'Luganda', themeId: 'Travail & Persévérance', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '199', text: "Quand tu manges, n'oublie pas celui qui a cultivé.", translation: "When you eat, do not forget the one who cultivated.", explanation: "La gratitude envers ceux qui ont rendu notre bien-être possible est essentielle.", countryId: 'ML', language: 'Bambara', themeId: 'Générosité & Partage', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '200', text: "La femme est la racine cachée de l'arbre familial.", translation: "The woman is the hidden root of the family tree.", explanation: "La femme est le soutien invisible mais indispensable de la famille.", countryId: 'CD', language: 'Lingala', themeId: 'Famille & Éducation', likesCount: 1510, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '201', text: "Celui qui plante des arbres dont il ne verra jamais l'ombre est sage.", translation: "He who plants trees whose shade he will never see is wise.", explanation: "La vraie sagesse consiste à agir pour les générations futures.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1430, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '202', text: "Le lion peut dormir, mais ses yeux restent ouverts dans son sommeil.", translation: "The lion may sleep, but its eyes stay open in its sleep.", explanation: "La vigilance ne se relâche jamais chez celui qui a la responsabilité de protéger.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '203', text: "La parole donnée est une dette que l'honneur exige de payer.", translation: "A word given is a debt that honor demands to pay.", explanation: "Tenir sa parole est une obligation morale fondamentale.", countryId: 'MA', language: 'Darija', themeId: 'Justice & Vérité', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '204', text: "Quand le baobab tombe, même les chèvres grimpent dessus.", translation: "When the baobab falls, even the goats climb on it.", explanation: "La chute des grands ouvre la voie aux plus petits.", countryId: 'GN', language: 'Peul', themeId: 'Leadership & Pouvoir', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '205', text: "Le canari ne se moque pas du pot de terre.", translation: "The china pot does not mock the earthen pot.", explanation: "Nul ne devrait se moquer de ceux qui lui ressemblent.", countryId: 'CI', language: 'Dioula', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '206', text: "L'habit ne fait pas le moine, mais il aide à le reconnaître.", translation: "The habit does not make the monk, but it helps identify him.", explanation: "L'apparence n'est pas la réalité, mais elle donne de premiers indices.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '207', text: "Qui voyage seul va plus vite, qui voyage ensemble va plus loin.", translation: "He who travels alone goes faster, he who travels together goes farther.", explanation: "La solidarité permet d'accomplir ce que l'effort solitaire ne peut atteindre.", countryId: 'AO', language: 'Kimbundu', themeId: 'Communauté & Entraide', likesCount: 1520, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '208', text: "La larme de l'orphelin n'arrose que sa propre joue.", translation: "The orphan's tear only waters his own cheek.", explanation: "La souffrance solitaire appelle à la solidarité des autres.", countryId: 'NG', language: 'Hausa', themeId: 'Communauté & Entraide', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '209', text: "Le feu peut dormir sous la cendre, mais il ne meurt jamais vraiment.", translation: "Fire can sleep under the ashes, but it never truly dies.", explanation: "L'esprit de résistance et la volonté de vivre sont indestructibles.", countryId: 'KE', language: 'Swahili', themeId: 'Espoir & Résilience', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '210', text: "Même la pierre finit par se creuser sous l'eau qui coule.", translation: "Even the stone is eventually hollowed by the flowing water.", explanation: "La persévérance tranquille triomphe des obstacles les plus solides.", countryId: 'MZ', language: 'Makua', themeId: 'Travail & Persévérance', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '211', text: "Les mauvaises herbes poussent sans qu'on les arrose.", translation: "Weeds grow without being watered.", explanation: "Le mal se répand facilement sans effort, contrairement au bien.", countryId: 'TZ', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  {id: '212', text: "Celui qui construit sur la terre des autres ne peut appeler la maison la sienne.", translation: "He who builds on another's land cannot call the house his own.", explanation: "L'indépendance et l'autonomie sont les fondements de la dignité.", countryId: 'BF', language: 'Mooré', themeId: 'Sagesse & Patience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '213', text: "La nuit révèle les étoiles que le jour cachait.", translation: "The night reveals the stars that the day had hidden.", explanation: "Les moments difficiles révèlent ce que la prospérité masquait.", countryId: 'ET', language: 'Amharique', themeId: 'Sagesse & Patience', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '214', text: "On ne peut pas empêcher le soleil de se lever en couvrant son visage.", translation: "You cannot stop the sun from rising by covering your face.", explanation: "Nier la réalité ne la fait pas disparaître.", countryId: 'ZA', language: 'Zulu', themeId: 'Justice & Vérité', likesCount: 1410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '215', text: "Le chasseur qui ne sait pas imiter les animaux rentre toujours les mains vides.", translation: "The hunter who cannot imitate animals always returns empty-handed.", explanation: "L'intelligence et l'adaptabilité sont les clés du succès.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Sagesse & Patience', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '216', text: "Un vrai chef est celui qui sert son peuple.", translation: "A true leader is one who serves his people.", explanation: "Le leadership authentique se manifeste dans le service et non dans le pouvoir.", countryId: 'GH', language: 'Twi', themeId: 'Leadership & Pouvoir', likesCount: 1480, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '217', text: "Ce n'est pas parce que l'arbre est grand qu'il ne peut tomber.", translation: "Just because the tree is tall does not mean it cannot fall.", explanation: "Même les plus puissants sont vulnérables.", countryId: 'CG', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '218', text: "L'ignorance est la nuit de l'esprit.", translation: "Ignorance is the night of the mind.", explanation: "Ne pas savoir plonge l'esprit dans les ténèbres comme la nuit plonge le monde.", countryId: 'SN', language: 'Wolof', themeId: 'Famille & Éducation', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '219', text: "Le chacal qui court après trop de proies reste affamé.", translation: "The jackal that chases too many prey remains hungry.", explanation: "La dispersion des efforts mène à l'échec et à l'insatisfaction.", countryId: 'ZM', language: 'Nyanja', themeId: 'Sagesse & Patience', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '220', text: "La honte est un fardeau que personne ne peut porter à ta place.", translation: "Shame is a burden no one can carry for you.", explanation: "Chacun doit assumer les conséquences de ses propres actes.", countryId: 'BJ', language: 'Fon', themeId: 'Justice & Vérité', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '221', text: "Là où les anciens se disputent, les jeunes doivent apporter l'eau pour calmer les feux.", translation: "Where elders quarrel, the young must bring water to calm the fires.", explanation: "La jeunesse a un rôle de médiation et d'apaisement dans les conflits.", countryId: 'ZW', language: 'Shona', themeId: 'Communauté & Entraide', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '222', text: "Le ventre vide n'a pas d'oreilles.", translation: "An empty belly has no ears.", explanation: "La faim et les besoins primaires empêchent toute réflexion ou écoute.", countryId: 'ML', language: 'Bambara', themeId: 'Sagesse & Patience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '223', text: "Même le vent le plus fort ne peut éteindre un cœur qui brûle pour la vérité.", translation: "Even the strongest wind cannot extinguish a heart that burns for truth.", explanation: "La conviction profonde résiste à toutes les pressions extérieures.", countryId: 'CM', language: 'Bamiléké', themeId: 'Justice & Vérité', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '224', text: "La vieille corde connaît le chemin du puits.", translation: "The old rope knows the way to the well.", explanation: "L'expérience guide mieux que la nouveauté dans les tâches répétées.", countryId: 'TG', language: 'Éwé', themeId: 'Identité & Héritage', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '225', text: "Ce n'est pas le sol qui fait pousser l'arbre, c'est la pluie et le soleil ensemble.", translation: "It is not the soil that makes the tree grow, it is the rain and the sun together.", explanation: "La croissance naît de la combinaison de plusieurs éléments complémentaires.", countryId: 'UG', language: 'Luganda', themeId: 'Communauté & Entraide', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '226', text: "Mieux vaut une paix fragile qu'une guerre certaine.", translation: "Better a fragile peace than a certain war.", explanation: "Même une paix imparfaite vaut mieux que la violence assurée.", countryId: 'CG', language: 'Kituba', themeId: 'Espoir & Résilience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '227', text: "L'intelligence d'un homme se mesure à la façon dont il traite ceux qui ne peuvent rien pour lui.", translation: "A man's intelligence is measured by how he treats those who can do nothing for him.", explanation: "La vraie noblesse se révèle dans le traitement des plus faibles.", countryId: 'NG', language: 'Yoruba', themeId: 'Sagesse & Patience', likesCount: 1490, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '228', text: "Le vent dispersé ne peut allumer le feu.", translation: "Scattered wind cannot light a fire.", explanation: "Il faut concentrer ses efforts pour produire un résultat.", countryId: 'KE', language: 'Swahili', themeId: 'Communauté & Entraide', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '229', text: "Chaque grain de sable compte pour faire le désert.", translation: "Every grain of sand counts to make the desert.", explanation: "Chaque contribution individuelle, aussi petite soit-elle, est indispensable.", countryId: 'MR', language: 'Hassaniya', themeId: 'Communauté & Entraide', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mauritanie' },
  { id: '230', text: "La vache qui n'a pas de veau croit que la boucherie est loin.", translation: "The cow without a calf thinks the slaughterhouse is far away.", explanation: "L'insouciance naît de l'ignorance du danger réel.", countryId: 'GN', language: 'Peul', themeId: 'Sagesse & Patience', likesCount: 1170, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '231', text: "Ce que tu offres à l'autre, c'est à toi-même que tu l'offres.", translation: "What you offer to another, you offer to yourself.", explanation: "La générosité enrichit celui qui donne autant que celui qui reçoit.", countryId: 'ET', language: 'Amharique', themeId: 'Générosité & Partage', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '232', text: "La pierre lancée à la lune retombe sur la tête du lanceur.", translation: "The stone thrown at the moon falls back on the head of the thrower.", explanation: "Le mal que l'on envoie nous revient toujours.", countryId: 'GA', language: 'Fang', themeId: 'Justice & Vérité', likesCount: 1300, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '233', text: "Le sage dit ce qu'il doit, non tout ce qu'il peut.", translation: "The wise man says what he must, not everything he can.", explanation: "La sagesse choisit ses mots avec soin et retenue.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '234', text: "Un peuple qui danse ensemble ne peut pas être brisé.", translation: "A people who dance together cannot be broken.", explanation: "La célébration collective renforce la cohésion et l'unité.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Communauté & Entraide', likesCount: 1440, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '235', text: "La chaleur du feu que tu as allumé profite à tout le voisinage.", translation: "The warmth of the fire you lit benefits the whole neighborhood.", explanation: "Nos bonnes actions rayonnent bien au-delà de notre cercle proche.", countryId: 'MZ', language: 'Makua', themeId: 'Générosité & Partage', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '236', text: "Même la plus belle rose a ses épines.", translation: "Even the most beautiful rose has its thorns.", explanation: "Rien n'est parfait ; toute beauté cache une part de difficulté.", countryId: 'MA', language: 'Darija', themeId: 'Sagesse & Patience', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '237', text: "L'enfant qui n'écoute pas son père deviendra un fardeau pour la société.", translation: "The child who does not listen to his father will become a burden to society.", explanation: "L'obéissance et le respect des aînés forment le citoyen de demain.", countryId: 'ZA', language: 'Zulu', themeId: 'Famille & Éducation', likesCount: 1210, isKidFriendly: false, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '238', text: "Il n'y a pas de raccourci sur le chemin de la sagesse.", translation: "There is no shortcut on the path of wisdom.", explanation: "La sagesse s'acquiert avec le temps et l'expérience, sans précipitation.", countryId: 'ML', language: 'Bambara', themeId: 'Sagesse & Patience', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '239', text: "On ne peut traverser le fleuve avec les bras croisés.", translation: "You cannot cross the river with folded arms.", explanation: "L'action et l'effort sont indispensables pour surmonter les obstacles.", countryId: 'BF', language: 'Mooré', themeId: 'Travail & Persévérance', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '240', text: "Celui qui pleure sans raison a une raison qu'il n'ose pas dire.", translation: "He who cries without reason has a reason he dare not say.", explanation: "Derrière chaque émotion inexpliquée se cache une souffrance inavouée.", countryId: 'BJ', language: 'Fon', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '241', text: "La mémoire des ancêtres est notre plus grande bibliothèque.", translation: "The memory of ancestors is our greatest library.", explanation: "Le savoir transmis par les générations passées est une richesse inestimable.", countryId: 'TZ', language: 'Swahili', themeId: 'Identité & Héritage', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '242', text: "Quand deux éléphants se battent, c'est l'herbe qui souffre.", translation: "When two elephants fight, it is the grass that suffers.", explanation: "Les conflits entre puissants causent toujours des dommages aux plus faibles.", countryId: 'KE', language: 'Swahili', themeId: 'Justice & Vérité', likesCount: 1470, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '243', text: "L'arbre qui a survécu à la tempête est celui qui a les racines les plus profondes.", translation: "The tree that survived the storm has the deepest roots.", explanation: "La résilience face à l'adversité forge les caractères les plus solides.", countryId: 'ZM', language: 'Bemba', themeId: 'Espoir & Résilience', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '244', text: "Parler à l'oreille d'un sourd est comme semer dans le désert.", translation: "Speaking into the ear of a deaf man is like sowing in the desert.", explanation: "Conseiller quelqu'un qui ne veut pas écouter est un effort vain.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '245', text: "Ce n'est pas la taille du tambour qui donne le rythme, c'est le batteur.", translation: "It is not the size of the drum that sets the rhythm, it is the drummer.", explanation: "C'est le talent et la maîtrise, non les moyens, qui font la différence.", countryId: 'GH', language: 'Twi', themeId: 'Sagesse & Patience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '246', text: "Le poisson ne voit pas l'eau dans laquelle il nage.", translation: "The fish does not see the water in which it swims.", explanation: "On ne perçoit pas ce qui nous est le plus familier.", countryId: 'CG', language: 'Kituba', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '247', text: "Même le roi doit manger pour vivre.", translation: "Even the king must eat to live.", explanation: "Tous les hommes, quelle que soit leur puissance, partagent les mêmes besoins fondamentaux.", countryId: 'NG', language: 'Hausa', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '248', text: "L'amour vrai ne se mesure pas aux mots mais aux actes.", translation: "True love is not measured by words but by deeds.", explanation: "Les actes d'amour comptent bien plus que les déclarations.", countryId: 'CI', language: 'Dioula', themeId: 'Amitié & Relations', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '249', text: "Un repas partagé a meilleur goût qu'un festin solitaire.", translation: "A shared meal tastes better than a solitary feast.", explanation: "La convivialité et le partage enrichissent chaque expérience.", countryId: 'UG', language: 'Luganda', themeId: 'Communauté & Entraide', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '250', text: "La peur d'échouer est le premier obstacle au succès.", translation: "The fear of failure is the first obstacle to success.", explanation: "Oser agir malgré la peur est la condition du succès.", countryId: 'CM', language: 'Ewondo', themeId: 'Espoir & Résilience', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '251', text: "Celui qui a chaud ne comprend pas celui qui a froid.", translation: "He who is warm does not understand he who is cold.", explanation: "On ne peut vraiment comprendre que ce que l'on a soi-même vécu.", countryId: 'TG', language: 'Éwé', themeId: 'Sagesse & Patience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '252', text: "La rivière qui refuse de couler finit par devenir un marécage.", translation: "A river that refuses to flow eventually becomes a swamp.", explanation: "Le refus d'avancer et de s'adapter conduit à la stagnation.", countryId: 'GN', language: 'Peul', themeId: 'Travail & Persévérance', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '253', text: "L'homme bon n'a pas besoin d'annoncer sa bonté.", translation: "The good man does not need to announce his goodness.", explanation: "La vraie vertu se manifeste par les actes, non par les paroles.", countryId: 'ET', language: 'Amharique', themeId: 'Sagesse & Patience', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  {id: '254', text: "Chaque nuit a son étoile particulière.", translation: "Every night has its particular star.", explanation: "Chaque moment difficile possède sa propre lumière et sa propre singularité.", countryId: 'AO', language: 'Kimbundu', themeId: 'Espoir & Résilience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '255', text: "Ce que tu sèmes en jeunesse, tu le récoltes en vieillesse.", translation: "What you sow in youth, you reap in old age.", explanation: "Les actions de la jeunesse déterminent les conditions de la vieillesse.", countryId: 'ZW', language: 'Shona', themeId: 'Justice & Vérité', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '256', text: "Un chef qui n'écoute pas son peuple finit seul.", translation: "A leader who does not listen to his people ends up alone.", explanation: "Le dialogue avec le peuple est la condition de la durabilité du pouvoir.", countryId: 'CD', language: 'Lingala', themeId: 'Leadership & Pouvoir', likesCount: 1430, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '257', text: "La colère est un feu qui brûle d'abord celui qui la ressent.", translation: "Anger is a fire that first burns the one who feels it.", explanation: "La colère non maîtrisée nuit avant tout à celui qui l'éprouve.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '258', text: "Même la fourmi a sa dignité.", translation: "Even the ant has its dignity.", explanation: "Chaque être, aussi petit soit-il, mérite le respect.", countryId: 'BF', language: 'Mooré', themeId: 'Justice & Vérité', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '259', text: "L'hospitalité est le premier devoir de l'homme africain.", translation: "Hospitality is the first duty of the African man.", explanation: "Accueillir l'autre avec chaleur est une valeur fondamentale en Afrique.", countryId: 'GA', language: 'Fang', themeId: 'Communauté & Entraide', likesCount: 1470, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '260', text: "La nuit sait ce que le jour ignore.", translation: "The night knows what the day ignores.", explanation: "Certaines vérités ne se révèlent que dans le silence et l'obscurité.", countryId: 'ML', language: 'Bambara', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '261', text: "Quand on mange ensemble, les mains se souviennent des mains.", translation: "When we eat together, hands remember other hands.", explanation: "Le partage du repas crée des liens durables entre les personnes.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Communauté & Entraide', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '262', text: "Ne brûle pas les ponts derrière toi, car tu pourrais avoir besoin de revenir.", translation: "Do not burn the bridges behind you, for you might need to return.", explanation: "Préserver les relations passées est une marque de prévoyance.", countryId: 'MA', language: 'Darija', themeId: 'Sagesse & Patience', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '263', text: "Ce que l'enfant voit faire, il le fait.", translation: "What the child sees done, he does.", explanation: "L'exemple des adultes est le premier enseignement de l'enfant.", countryId: 'NG', language: 'Yoruba', themeId: 'Famille & Éducation', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '264', text: "La richesse sans sagesse est une maison sans fondations.", translation: "Wealth without wisdom is a house without foundations.", explanation: "L'argent seul ne suffit pas sans la sagesse pour le gérer.", countryId: 'KE', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '265', text: "Le chant de l'oiseau à l'aube annonce la fin de la nuit.", translation: "The bird's song at dawn announces the end of night.", explanation: "Les signes précurseurs annoncent toujours les changements à venir.", countryId: 'TZ', language: 'Swahili', themeId: 'Espoir & Résilience', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '266', text: "Un peuple sans mémoire est un peuple mort.", translation: "A people without memory is a dead people.", explanation: "La mémoire collective est l'âme et la vie d'une nation.", countryId: 'ZA', language: 'Zulu', themeId: 'Identité & Héritage', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '267', text: "La générosité sans discernement appauvrit deux fois.", translation: "Generosity without discernment impoverishes twice.", explanation: "Donner sans sagesse peut nuire autant à celui qui donne qu'à celui qui reçoit.", countryId: 'CM', language: 'Bamiléké', themeId: 'Générosité & Partage', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '268', text: "Même le soleil a ses éclipses.", translation: "Even the sun has its eclipses.", explanation: "Même les plus grands traversent des périodes d'obscurité.", countryId: 'MZ', language: 'Makua', themeId: 'Espoir & Résilience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '269', text: "La bouche du sage n'ouvre que lorsque le cœur a bien réfléchi.", translation: "The wise man's mouth opens only when the heart has reflected well.", explanation: "La parole sage naît d'une longue réflexion intérieure.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '270', text: "Le miel de la ruche lointaine est toujours plus doux.", translation: "The honey from the distant hive always seems sweeter.", explanation: "Ce qui est loin ou difficile d'accès paraît toujours plus désirable.", countryId: 'GN', language: 'Peul', themeId: 'Sagesse & Patience', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '271', text: "Ce que tu caches en toi se voit sur ton visage.", translation: "What you hide inside yourself shows on your face.", explanation: "Les émotions et les pensées se lisent toujours sur le visage.", countryId: 'CG', language: 'Kituba', themeId: 'Justice & Vérité', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '272', text: "L'homme libre est celui qui sait contrôler ses désirs.", translation: "The free man is the one who knows how to control his desires.", explanation: "La vraie liberté réside dans la maîtrise de soi et non dans l'absence de contraintes.", countryId: 'ET', language: 'Amharique', themeId: 'Sagesse & Patience', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '273', text: "La force de la communauté réside dans chaque individu.", translation: "The strength of the community lies in each individual.", explanation: "La collectivité ne peut être forte que si chacun de ses membres l'est aussi.", countryId: 'ZM', language: 'Nyanja', themeId: 'Communauté & Entraide', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '274', text: "Même le vent doit s'incliner devant la montagne.", translation: "Even the wind must bow before the mountain.", explanation: "Certaines forces et certaines vérités s'imposent à toutes les puissances.", countryId: 'BJ', language: 'Fon', themeId: 'Sagesse & Patience', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '275', text: "On ne bâtit pas une nation sur la peur mais sur la confiance.", translation: "A nation is not built on fear but on trust.", explanation: "La confiance mutuelle est le fondement de toute société solide.", countryId: 'ZW', language: 'Shona', themeId: 'Leadership & Pouvoir', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '276', text: "L'horizon est toujours devant celui qui marche.", translation: "The horizon is always ahead of the one who walks.", explanation: "Tant que l'on avance, les objectifs et les rêves restent à portée.", countryId: 'ML', language: 'Bambara', themeId: 'Travail & Persévérance', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '277', text: "La santé vaut mieux que toutes les richesses du monde.", translation: "Health is worth more than all the riches in the world.", explanation: "Sans la santé, aucune richesse ne peut être pleinement appréciée.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1450, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '278', text: "Un mensonge dit mille fois reste un mensonge.", translation: "A lie said a thousand times remains a lie.", explanation: "La répétition ne transforme jamais le faux en vrai.", countryId: 'TG', language: 'Éwé', themeId: 'Justice & Vérité', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '279', text: "La femme qui porte l'enfant dans son dos voit ce qui est devant.", translation: "The woman who carries the child on her back sees what is ahead.", explanation: "La femme, tout en prenant soin des siens, garde la vision de l'avenir.", countryId: 'UG', language: 'Luganda', themeId: 'Famille & Éducation', likesCount: 1490, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '280', text: "Ne cherche pas à cueillir le fruit avant qu'il ne soit mûr.", translation: "Do not try to pick the fruit before it is ripe.", explanation: "La précipitation gâche ce que la patience aurait rendu parfait.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '281', text: "Le guerrier ne se prépare pas avant la bataille, mais bien avant.", translation: "The warrior does not prepare before the battle, but long before.", explanation: "La préparation anticipée est la clé de toute victoire.", countryId: 'GH', language: 'Twi', themeId: 'Sagesse & Patience', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },  
  { id: '282', text: "Ce n'est pas l'orage qui dure, c'est la terre qui l'absorbe.", translation: "It is not the storm that lasts, it is the earth that absorbs it.", explanation: "La résilience et l'endurance triomphent toujours des tempêtes passagères.", countryId: 'CI', language: 'Dioula', themeId: 'Espoir & Résilience', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '283', text: "L'homme qui connaît sa valeur n'a pas besoin que les autres la lui rappellent.", translation: "The man who knows his worth does not need others to remind him.", explanation: "La confiance en soi rend indépendant du regard des autres.", countryId: 'NG', language: 'Igbo', themeId: 'Sagesse & Patience', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '284', text: "Quand la termite vole, sa tombe est déjà creusée.", translation: "When the termite flies, its grave is already dug.", explanation: "Certaines actions téméraires annoncent inévitablement la fin.", countryId: 'CD', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '285', text: "La connaissance d'un seul homme enrichit tout un village.", translation: "The knowledge of one man enriches an entire village.", explanation: "Le partage du savoir bénéficie à toute la communauté.", countryId: 'KE', language: 'Swahili', themeId: 'Communauté & Entraide', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '286', text: "L'arbre se redresse quand il est encore jeune.", translation: "The tree straightens when it is still young.", explanation: "Il est plus facile de corriger et d'éduquer un enfant qu'un adulte.", countryId: 'CM', language: 'Ewondo', themeId: 'Famille & Éducation', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '287', text: "Un ami sincère est plus précieux que mille admirateurs.", translation: "A sincere friend is more precious than a thousand admirers.", explanation: "La qualité d'une amitié vaut bien plus que la quantité de relations.", countryId: 'MA', language: 'Darija', themeId: 'Amitié & Relations', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '288', text: "Le lion ne rugit pas pour rien.", translation: "The lion does not roar for nothing.", explanation: "Quand les grands s'expriment, c'est que la situation est sérieuse.", countryId: 'BF', language: 'Mooré', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '289', text: "La vie est un voyage dont personne ne connaît la destination.", translation: "Life is a journey whose destination no one knows.", explanation: "L'incertitude de l'avenir invite à savourer chaque étape du chemin.", countryId: 'SN', language: 'Wolof', themeId: 'Sagesse & Patience', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '290', text: "Ce qui se construit dans la paix dure plus longtemps.", translation: "What is built in peace lasts longer.", explanation: "La sérénité et la stabilité sont les meilleures conditions pour créer.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Espoir & Résilience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '291', text: "Le passé est une leçon, le présent une action, l'avenir une espérance.", translation: "The past is a lesson, the present an action, the future a hope.", explanation: "Chaque dimension du temps a sa propre fonction dans la vie humaine.", countryId: 'TZ', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '292', text: "Même le plus grand chasseur a besoin d'un guide dans une forêt inconnue.", translation: "Even the greatest hunter needs a guide in an unfamiliar forest.", explanation: "L'humilité consiste à reconnaître les limites de son propre savoir.", countryId: 'MZ', language: 'Makua', themeId: 'Sagesse & Patience', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '293', text: "Un enfant qui danse connaît sa musique intérieure.", translation: "A child who dances knows its inner music.", explanation: "L'expression naturelle révèle la richesse intérieure de chaque être.", countryId: 'AO', language: 'Kimbundu', themeId: 'Famille & Éducation', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '294', text: "La sagesse est un don que les années seules peuvent offrir.", translation: "Wisdom is a gift that only the years can give.", explanation: "La sagesse véritable ne s'acquiert qu'avec le temps et l'expérience.", countryId: 'ML', language: 'Bambara', themeId: 'Sagesse & Patience', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '295', text: "Ce que le cœur ressent, les yeux le montrent.", translation: "What the heart feels, the eyes show.", explanation: "Les émotions profondes se lisent toujours dans le regard.", countryId: 'ET', language: 'Amharique', themeId: 'Sagesse & Patience', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '296', text: "Le rocher ne craint pas la pluie.", translation: "The rock does not fear the rain.", explanation: "La vraie force intérieure résiste à toutes les épreuves extérieures.", countryId: 'NG', language: 'Yoruba', themeId: 'Espoir & Résilience', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '297', text: "Une bonne action efface mille mauvaises.", translation: "One good deed erases a thousand bad ones.", explanation: "La rédemption est toujours possible par les actes positifs.", countryId: 'GN', language: 'Peul', themeId: 'Générosité & Partage', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '298', text: "L'eau douce et l'eau salée ne se mélangent jamais vraiment.", translation: "Fresh water and salt water never truly mix.", explanation: "Certaines différences sont fondamentales et ne peuvent être effacées.", countryId: 'CG', language: 'Lingala', themeId: 'Sagesse & Patience', likesCount: 1180, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '299', text: "La maison est là où le cœur est en paix.", translation: "Home is where the heart is at peace.", explanation: "La vraie maison n'est pas un lieu mais un état intérieur de sérénité.", countryId: 'KE', language: 'Swahili', themeId: 'Famille & Éducation', likesCount: 1430, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '300', text: "Qui prend les décisions pour tous doit écouter tout le monde.", translation: "He who makes decisions for all must listen to everyone.", explanation: "La gouvernance juste exige une écoute attentive de toutes les voix.", countryId: 'GH', language: 'Twi', themeId: 'Leadership & Pouvoir', likesCount: 1460, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '301', text: "Le crocodile qui dort n'attrape pas de poissons.", translation: "The sleeping crocodile does not catch fish.", explanation: "L'inaction et la passivité font manquer les opportunités.", countryId: 'ZM', language: 'Bemba', themeId: 'Travail & Persévérance', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '302', text: "L'enfant bien élevé est la fierté de deux familles.", translation: "A well-raised child is the pride of two families.", explanation: "La bonne éducation d'un enfant rejaillit sur toute sa lignée.", countryId: 'BJ', language: 'Fon', themeId: 'Famille & Éducation', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '303', text: "Ce n'est pas parce que la foudre n'a pas encore frappé qu'elle ne viendra pas.", translation: "Just because lightning has not yet struck does not mean it will not come.", explanation: "L'absence de danger immédiat ne signifie pas l'absence de danger.", countryId: 'CI', language: 'Dioula', themeId: 'Sagesse & Patience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '304', text: "La parole vraie ne craint pas le silence.", translation: "True words do not fear silence.", explanation: "La vérité n'a pas besoin d'être répétée pour s'imposer.", countryId: 'TG', language: 'Éwé', themeId: 'Justice & Vérité', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' }, 
  { id: '305', text: "Un homme qui aide son voisin construit sa propre demeure.", translation: "A man who helps his neighbor builds his own home.", explanation: "L'entraide mutuelle profite à toute la communauté, y compris à celui qui aide.", countryId: 'ZW', language: 'Shona', themeId: 'Communauté & Entraide', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '306', text: "Le chemin est long, mais chaque pas rapproche du but.", translation: "The road is long, but every step brings you closer to the goal.", explanation: "La persévérance progressive mène inévitablement à la réussite.", countryId: 'ZA', language: 'Zulu', themeId: 'Travail & Persévérance', likesCount: 1400, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '307', text: "Ne mets jamais tes espoirs sur une seule récolte.", translation: "Never place all your hopes on a single harvest.", explanation: "La diversification des efforts protège contre les coups du sort.", countryId: 'UG', language: 'Luganda', themeId: 'Sagesse & Patience', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '308', text: "L'amour est comme un arbre qui doit être arrosé chaque jour.", translation: "Love is like a tree that must be watered every day.", explanation: "L'amour durable demande des soins et une attention constante.", countryId: 'MA', language: 'Darija', themeId: 'Amitié & Relations', likesCount: 1490, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '309', text: "La frontière entre la sagesse et la folie est parfois très mince.", translation: "The boundary between wisdom and folly is sometimes very thin.", explanation: "Ce qui paraît insensé peut se révéler sage, et inversement.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '310', text: "Même le plus beau chant s'arrête.", translation: "Even the most beautiful song ends.", explanation: "Toute chose belle est éphémère ; il faut en profiter pleinement.", countryId: 'CM', language: 'Ewondo', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '311', text: "L'herbe sèche peut devenir l'ami du feu ou du vent.", translation: "Dry grass can become the friend of fire or wind.", explanation: "Un même élément peut être utile ou destructeur selon les circonstances.", countryId: 'ML', language: 'Bambara', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '312', text: "Celui qui ne remercie pas les hommes ne remercie pas Dieu.", translation: "He who does not thank men does not thank God.", explanation: "La gratitude envers les autres est le fondement de la spiritualité.", countryId: 'SN', language: 'Wolof', themeId: 'Générosité & Partage', likesCount: 1410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '313', text: "La peau de la panthère ne change pas avec les saisons.", translation: "The panther's skin does not change with the seasons.", explanation: "La nature profonde d'un être ne change pas avec les circonstances.", countryId: 'NG', language: 'Yoruba', themeId: 'Sagesse & Patience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '314', text: "Un peuple sans dignité est un peuple sans avenir.", translation: "A people without dignity is a people without a future.", explanation: "La dignité collective est la condition de tout développement durable.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Identité & Héritage', likesCount: 1440, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' },
  { id: '315', text: "Les mots doux font avancer même le mulet têtu.", translation: "Sweet words make even the stubborn mule move forward.", explanation: "La douceur et la bienveillance sont plus efficaces que la force.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '316', text: "La mémoire est le trésor de ceux qui n'ont rien d'autre.", translation: "Memory is the treasure of those who have nothing else.", explanation: "Pour ceux qui ont tout perdu, la mémoire est leur unique richesse.", countryId: 'CG', language: 'Kituba', themeId: 'Identité & Héritage', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '317', text: "Il vaut mieux plier que rompre.", translation: "It is better to bend than to break.", explanation: "La souplesse et l'adaptation permettent de surmonter les épreuves sans se briser.", countryId: 'BF', language: 'Mooré', themeId: 'Sagesse & Patience', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '318', text: "L'esclave libéré qui retourne à ses chaînes choisit sa prison.", translation: "The freed slave who returns to his chains chooses his prison.", explanation: "Renoncer à sa liberté est la pire des trahisons envers soi-même.", countryId: 'MZ', language: 'Makua', themeId: 'Espoir & Résilience', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '319', text: "Ce n'est pas la grandeur de la tâche qui décourage, c'est le manque de foi.", translation: "It is not the greatness of the task that discourages, it is the lack of faith.", explanation: "La foi en ses capacités est le premier moteur de la réussite.", countryId: 'ET', language: 'Amharique', themeId: 'Espoir & Résilience', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '320', text: "La sagesse ne se reçoit pas en héritage, elle se mérite.", translation: "Wisdom is not received as an inheritance; it must be earned.", explanation: "La sagesse exige un effort personnel et ne peut s'acquérir par transmission passive.", countryId: 'TZ', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '321', text: "Même le plus grand voyage a un commencement et une fin.", translation: "Even the greatest journey has a beginning and an end.", explanation: "Tout dans la vie a une durée limitée ; il faut en profiter pleinement.", countryId: 'KE', language: 'Swahili', themeId: 'Sagesse & Patience', likesCount: 1250, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '322', text: "L'homme généreux ne compte jamais ce qu'il donne.", translation: "The generous man never counts what he gives.", explanation: "La vraie générosité est inconditionnelle et sans calcul.", countryId: 'GH', language: 'Twi', themeId: 'Générosité & Partage', likesCount: 1390, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '323', text: "La parole semée dans l'enfance fleurit dans la vieillesse.", translation: "Words sown in childhood bloom in old age.", explanation: "Les enseignements de l'enfance portent leurs fruits toute la vie.", countryId: 'BJ', language: 'Fon', themeId: 'Famille & Éducation', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '324', text: "Quand les larmes sèchent, la sagesse peut parler.", translation: "When tears dry, wisdom can speak.", explanation: "Le calme retrouvé après la douleur ouvre la voie à la réflexion sage.", countryId: 'CI', language: 'Dioula', themeId: 'Sagesse & Patience', likesCount: 1270, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Côte d\'Ivoire' },
  { id: '325', text: "Le chef qui ne connaît pas son peuple est un berger aveugle.", translation: "The leader who does not know his people is a blind shepherd.", explanation: "Gouverner exige une connaissance profonde de ceux que l'on dirige.", countryId: 'ZM', language: 'Bemba', themeId: 'Leadership & Pouvoir', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zambie' },
  { id: '326', text: "La chance sourit à celui qui se lève avant le soleil.", translation: "Luck smiles upon the one who rises before the sun.", explanation: "L'effort précoce et la diligence attirent les opportunités.", countryId: 'GN', language: 'Peul', themeId: 'Travail & Persévérance', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée' },
  { id: '327', text: "Ce que tu dis à l'aube, le vent l'emporte jusqu'au soir.", translation: "What you say at dawn, the wind carries until evening.", explanation: "Les paroles prononcées se propagent et ont des conséquences durables.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1210, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '328', text: "L'amour de la patrie ne se discute pas, il se vit.", translation: "Love of the homeland is not discussed, it is lived.", explanation: "L'attachement à sa terre et à son peuple se manifeste dans les actes.", countryId: 'ZA', language: 'Zulu', themeId: 'Identité & Héritage', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '329', text: "Un enfant qui grandit entre les femmes apprend la douceur.", translation: "A child who grows up among women learns gentleness.", explanation: "L'entourage maternel et féminin transmet des valeurs de douceur et d'empathie.", countryId: 'ML', language: 'Bambara', themeId: 'Famille & Éducation', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '330', text: "Même la montagne s'incline devant la rivière qui la creuse.", translation: "Even the mountain bows before the river that carves it.", explanation: "La persévérance patient finit par triompher même des obstacles les plus imposants.", countryId: 'AO', language: 'Kimbundu', themeId: 'Travail & Persévérance', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Angola' },
  { id: '331', text: "Le mensonge habillé en vérité trompe même les plus sages.", translation: "A lie dressed as truth deceives even the wisest.", explanation: "L'imposture habilement déguisée peut tromper les esprits les plus avisés.", countryId: 'MA', language: 'Darija', themeId: 'Justice & Vérité', likesCount: 1300, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '332', text: "Là où il y a de l'unité, il y a toujours de la force.", translation: "Where there is unity, there is always strength.", explanation: "L'union des individus crée une force collective invincible.", countryId: 'NG', language: 'Hausa', themeId: 'Communauté & Entraide', likesCount: 1450, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '333', text: "La rivière a de la mémoire : elle se souvient de chaque roche qu'elle a contournée.", translation: "The river has memory: it remembers every rock it has navigated around.", explanation: "L'expérience accumulée guide nos actions face aux obstacles.", countryId: 'CG', language: 'Lingala', themeId: 'Identité & Héritage', likesCount: 1220, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
  { id: '334', text: "L'homme qui n'a pas peur de la nuit voit les étoiles que les autres manquent.", translation: "The man who is not afraid of the night sees the stars others miss.", explanation: "Le courage face à l'obscurité révèle des beautés cachées.", countryId: 'RW', language: 'Kinyarwanda', themeId: 'Espoir & Résilience', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Rwanda' }, 
  { id: '335', text: "Ce qui brûle vite s'éteint vite.", translation: "What burns fast is extinguished fast.", explanation: "L'enthousiasme ou la colère qui s'embrase rapidement ne dure guère.", countryId: 'CM', language: 'Ewondo', themeId: 'Sagesse & Patience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '336', text: "La valeur d'une chose se voit souvent après sa perte.", translation: "The value of a thing is often seen after its loss.", explanation: "On apprécie rarement ce que l'on possède avant de l'avoir perdu.", countryId: 'TG', language: 'Éwé', themeId: 'Générosité & Partage', likesCount: 1310, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Togo' },
  { id: '337', text: "Un vieux filet connaît tous les poissons du lac.", translation: "An old net knows all the fish in the lake.", explanation: "L'expérience longue confère une connaissance que la jeunesse ne peut avoir.", countryId: 'KE', language: 'Swahili', themeId: 'Identité & Héritage', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Kenya' },
  { id: '338', text: "Chaque arbre a son ombre propre.", translation: "Every tree has its own shadow.", explanation: "Chaque être a sa propre identité et sa propre influence dans le monde.", countryId: 'TZ', language: 'Swahili', themeId: 'Identité & Héritage', likesCount: 1200, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Tanzanie' },
  { id: '339', text: "L'hospitalité commence par le sourire avant même le repas.", translation: "Hospitality begins with a smile even before the meal.", explanation: "L'accueil chaleureux prime sur les moyens matériels d'hospitalité.", countryId: 'ET', language: 'Amharique', themeId: 'Communauté & Entraide', likesCount: 1370, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Éthiopie' },
  { id: '340', text: "Même le vent du nord finit par se réchauffer en chemin.", translation: "Even the north wind eventually warms up along the way.", explanation: "Tout peut changer avec le temps ; rien n'est figé pour toujours.", countryId: 'BF', language: 'Mooré', themeId: 'Espoir & Résilience', likesCount: 1280, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Burkina Faso' },
  { id: '341', text: "Ne juge pas la forêt par un seul arbre.", translation: "Do not judge the forest by a single tree.", explanation: "Il faut considérer l'ensemble avant de porter un jugement.", countryId: 'GW', language: 'Crioulo', themeId: 'Sagesse & Patience', likesCount: 1230, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Guinée-Bissau' },
  { id: '342', text: "L'homme qui se vante de ses ancêtres est comme une patate douce qui pousse sur les mérites d'une autre.", translation: "The man who boasts of his ancestors is like a sweet potato growing on another's merits.", explanation: "Se glorifier des mérites des autres sans valeur propre est une forme de vanité.", countryId: 'ZW', language: 'Shona', themeId: 'Sagesse & Patience', likesCount: 1190, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Zimbabwe' },
  { id: '343', text: "La bonne graine pousse même dans une mauvaise terre.", translation: "A good seed grows even in bad soil.", explanation: "Le talent et la vertu s'épanouissent malgré les conditions défavorables.", countryId: 'GH', language: 'Twi', themeId: 'Espoir & Résilience', likesCount: 1340, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ghana' },
  { id: '344', text: "Celui qui guide les autres doit d'abord savoir se guider lui-même.", translation: "He who guides others must first know how to guide himself.", explanation: "La maîtrise de soi est la condition préalable au leadership.", countryId: 'SN', language: 'Wolof', themeId: 'Leadership & Pouvoir', likesCount: 1410, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Sénégal' },
  { id: '345', text: "Le champ demande du travail, non des prières seules.", translation: "The field demands work, not prayers alone.", explanation: "L'effort humain est indispensable ; la foi seule ne suffit pas.", countryId: 'UG', language: 'Luganda', themeId: 'Travail & Persévérance', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Ouganda' },
  { id: '346', text: "Une douleur partagée est une douleur allégée.", translation: "A shared pain is a lightened pain.", explanation: "Le soutien mutuel allège les souffrances de chacun.", countryId: 'MZ', language: 'Makua', themeId: 'Communauté & Entraide', likesCount: 1380, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mozambique' },
  { id: '347', text: "Le sage parle avec son cœur, le fou avec sa bouche.", translation: "The wise speaks with his heart, the fool with his mouth.", explanation: "La sagesse réfléchit avant de parler, la folie parle sans réfléchir.", countryId: 'DZ', language: 'Tamazight', themeId: 'Sagesse & Patience', likesCount: 1260, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Algérie' },
  { id: '348', text: "La vérité est la seule chose que personne ne peut voler.", translation: "Truth is the only thing no one can steal.", explanation: "La vérité appartient à tout le monde et ne peut être appropriée ni détruite.", countryId: 'BJ', language: 'Fon', themeId: 'Justice & Vérité', likesCount: 1420, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Bénin' },
  { id: '349', text: "Même la nuit la plus sombre a une étoile qui veille.", translation: "Even the darkest night has a star keeping watch.", explanation: "Dans les pires moments, il reste toujours un espoir ou un soutien.", countryId: 'CD', language: 'Lingala', themeId: 'Espoir & Résilience', likesCount: 1470, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'RDC' },
  { id: '350', text: "L'honneur d'une famille est entre les mains de chaque membre.", translation: "The honor of a family is in the hands of each member.", explanation: "La réputation familiale dépend du comportement de chacun.", countryId: 'MA', language: 'Darija', themeId: 'Famille & Éducation', likesCount: 1350, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Maroc' },
  { id: '351', text: "Quand tu construis une maison pour ton ennemi, tu te construis une prison.", translation: "When you build a house for your enemy, you build yourself a prison.", explanation: "La haine et la rancœur envers autrui nous emprisonnent nous-mêmes.", countryId: 'GA', language: 'Fang', themeId: 'Sagesse & Patience', likesCount: 1290, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Gabon' },
  { id: '352', text: "L'enfant qui écoute grandit sage; celui qui parle trop grandit seul.", translation: "The child who listens grows wise; the one who talks too much grows alone.", explanation: "L'écoute attentive est source de sagesse et de relations durables.", countryId: 'CM', language: 'Bamiléké', themeId: 'Famille & Éducation', likesCount: 1320, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Cameroun' },
  { id: '353', text: "Le lion affamé n'attend pas que le gibier vienne à lui.", translation: "The hungry lion does not wait for game to come to it.", explanation: "Quand la situation est urgente, l'initiative et l'action s'imposent.", countryId: 'NG', language: 'Yoruba', themeId: 'Travail & Persévérance', likesCount: 1360, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Nigeria' },
  { id: '354', text: "La faiblesse n'est pas dans la chute, mais dans le refus de se relever.", translation: "Weakness is not in the fall, but in the refusal to get up.", explanation: "La vraie défaite est l'abandon ; tomber est humain mais se relever est héroïque.", countryId: 'ZA', language: 'Zulu', themeId: 'Espoir & Résilience', likesCount: 1490, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Afrique du Sud' },
  { id: '355', text: "La terre nourrit ceux qui la travaillent et oublie les paresseux.", translation: "The earth nourishes those who work it and forgets the lazy.", explanation: "La récompense appartient à ceux qui fournissent l'effort.", countryId: 'ML', language: 'Bambara', themeId: 'Travail & Persévérance', likesCount: 1330, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Mali' },
  { id: '356', text: "Ce que l'aigle voit du haut, la souris ne le verra jamais d'en bas.", translation: "What the eagle sees from above, the mouse will never see from below.", explanation: "La perspective et la position déterminent ce que l'on peut percevoir.", countryId: 'CG', language: 'Kituba', themeId: 'Sagesse & Patience', likesCount: 1240, isKidFriendly: true, createdAt: new Date().toISOString(), originCountryName: 'Congo' },
];

